const tree = {"name":"cancel","value":27187,"children":[{"name":"cancel","value":27187,"children":[{"name":"entrypoint @ 0x2282","value":27187,"children":[{"name":"clear_msig_anchor::entry @ 0x1efc","value":27139,"children":[{"name":"<clear_msig_anchor::instructions::cancel::Cancel as anchor_lang_v2::dispatch::TryAccounts>::try_accounts @ 0x1b5b","value":198,"children":[]},{"name":"[syscall] sol_log_","value":1,"children":[]},{"name":"cancel::Cancel::cancel @ 0x2ee","value":26783,"children":[{"name":"[syscall] syscall_0x13c1b505","value":1,"children":[]},{"name":"brine_ed25519::sig_verify @ 0x240c","value":25225,"children":[{"name":"edwards::target_arch::multiply_edwards @ 0x2637","value":100,"children":[{"name":"[syscall] sol_curve_group_op","value":4,"children":[]}]},{"name":"edwards::target_arch::subtract_edwards @ 0x261e","value":25,"children":[{"name":"[syscall] sol_curve_group_op","value":1,"children":[]}]},{"name":"edwards::target_arch::validate_edwards @ 0x2613","value":20,"children":[{"name":"[syscall] sol_curve_validate_point","value":2,"children":[]}]},{"name":"memcpy @ 0x575c","value":16,"children":[{"name":"[syscall] sol_memcpy_","value":4,"children":[]}]},{"name":"memset @ 0x5760","value":10,"children":[{"name":"[syscall] sol_memset_","value":2,"children":[]}]},{"name":"scalar::Scalar::from_bytes_mod_order_wide @ 0x2653","value":5699,"children":[{"name":"scalar::Scalar52::montgomery_mul @ 0x2c71","value":5302,"children":[{"name":"__multi3 @ 0x5ab6","value":3489,"children":[]}]}]},{"name":"scalar::Scalar::from_canonical_bytes @ 0x27ec","value":3373,"children":[{"name":"scalar::Scalar::reduce @ 0x2860","value":2788,"children":[{"name":"__multi3 @ 0x5ab6","value":1748,"children":[]},{"name":"scalar::Scalar::unpack @ 0x281d","value":66,"children":[]}]},{"name":"subtle::black_box @ 0x2650","value":105,"children":[]}]},{"name":"sha2::sha512::compress512 @ 0x3029","value":15594,"children":[]}]},{"name":"memset @ 0x5760","value":5,"children":[{"name":"[syscall] sol_memset_","value":1,"children":[]}]},{"name":"message::MessageBuilder::build_message_for_intent @ 0xdcd","value":1421,"children":[{"name":"message::MessageBuilder::build_remove_intent_message @ 0x115a","value":1387,"children":[{"name":"memcpy @ 0x575c","value":4,"children":[{"name":"[syscall] sol_memcpy_","value":1,"children":[]}]},{"name":"message::MessageBuilder::push_header @ 0xd83","value":1259,"children":[{"name":"memcpy @ 0x575c","value":4,"children":[{"name":"[syscall] sol_memcpy_","value":1,"children":[]}]},{"name":"utils::datetime::format_timestamp @ 0xbb7","value":1192,"children":[{"name":"__divdi3 @ 0x5aa1","value":999,"children":[{"name":"int::specialized_div_rem::u64_div_rem @ 0x5a07","value":793,"children":[]}]}]}]},{"name":"message::MessageBuilder::push_u64 @ 0xc80","value":54,"children":[{"name":"memcpy @ 0x575c","value":4,"children":[{"name":"[syscall] sol_memcpy_","value":1,"children":[]}]}]}]}]}]},{"name":"memcpy @ 0x575c","value":8,"children":[{"name":"[syscall] sol_memcpy_","value":2,"children":[]}]}]}]}]}]};
const SVG_NS = "http://www.w3.org/2000/svg";
const FRAME_HEIGHT = 22;
const FRAME_GAP = 1;
const SIDE_PADDING = 8;
const TOP_PADDING = 54;
const BOTTOM_PADDING = 12;
const SVG_WIDTH = 1600;
const SVG_HEIGHT = 319;
const INNER_WIDTH = SVG_WIDTH - SIDE_PADDING * 2;
const PROGRAM_NAME = "cancel";
const TOTAL_CU = 27187;

let focusPath = [];

function getNode(path) {
  let node = tree;
  for (const index of path) {
    node = node.children[index];
  }
  return node;
}

function maxDepth(node) {
  if (!node.children.length) {
    return 0;
  }
  let depth = 0;
  for (const child of node.children) {
    depth = Math.max(depth, 1 + maxDepth(child));
  }
  return depth;
}

function focusName() {
  return focusPath.length ? getNode(focusPath).name : PROGRAM_NAME;
}

function updateHeader() {
  const subtitle = document.getElementById("subtitle");
  const resetButton = document.getElementById("reset-button");
  subtitle.textContent = focusPath.length
    ? `Focused: ${focusName()} | Total CU: ${TOTAL_CU}`
    : `Total CU: ${TOTAL_CU}`;
  resetButton.style.opacity = focusPath.length ? "1" : "0.55";
}

function resetZoom(event) {
  if (event) {
    event.stopPropagation();
  }
  focusPath = [];
  renderFrames();
}

function zoomTo(path, event) {
  if (event) {
    event.stopPropagation();
  }
  focusPath = path.slice();
  renderFrames();
}

function truncateLabel(label, width) {
  const maxChars = Math.floor(width / 7);
  if (maxChars < 4 || label.length <= maxChars) {
    return label;
  }
  return label.slice(0, maxChars - 3) + "...";
}

function hashLabel(label) {
  let hash = 2166136261 >>> 0;
  for (let index = 0; index < label.length; index += 1) {
    hash ^= label.charCodeAt(index);
    hash = Math.imul(hash, 16777619) >>> 0;
  }
  return hash >>> 0;
}

function frameColor(label) {
  const t = (hashLabel(label) % 10000) / 10000;
  const red = 255;
  const green = Math.round(235 + (52 - 235) * t);
  const blue = Math.round(130 + (0 - 130) * t);
  return { red, green, blue };
}

function colorToCss(color) {
  return `rgb(${color.red}, ${color.green}, ${color.blue})`;
}

function labelColor(color) {
  const luminance = (0.299 * color.red + 0.587 * color.green + 0.114 * color.blue) / 255;
  return luminance < 0.52 ? "#fffdf8" : "#2b1600";
}

function createSvgElement(tagName, attributes = {}) {
  const element = document.createElementNS(SVG_NS, tagName);
  for (const [name, value] of Object.entries(attributes)) {
    element.setAttribute(name, String(value));
  }
  return element;
}

function renderNode(parent, node, depth, x, width, subtreeDepth, path) {
  if (!node.value || width <= 0.5) {
    return;
  }

  const y = TOP_PADDING + (subtreeDepth - depth) * (FRAME_HEIGHT + FRAME_GAP);
  const fillColor = frameColor(node.name);
  const label = `${node.name} (${node.value})`;
  const group = createSvgElement("g");
  const title = createSvgElement("title");
  title.textContent = label;
  group.appendChild(title);

  const rect = createSvgElement("rect", {
    x,
    y,
    width,
    height: FRAME_HEIGHT,
    fill: colorToCss(fillColor),
    stroke: "#ffffff",
    "stroke-width": 1,
  });
  group.appendChild(rect);

  if (path.length || node.children.length) {
    group.style.cursor = "pointer";
    group.addEventListener("click", (event) => zoomTo(path, event));
  }

  if (width > 48) {
    const text = createSvgElement("text", {
      x: x + 6,
      y: y + FRAME_HEIGHT / 2,
      "dominant-baseline": "middle",
      "font-family": "monospace",
      "font-size": 12,
      fill: labelColor(fillColor),
    });
    text.textContent = truncateLabel(label, width);
    group.appendChild(text);
  }

  parent.appendChild(group);

  let childX = x;
  for (let index = 0; index < node.children.length; index += 1) {
    const child = node.children[index];
    const childWidth = width * (child.value / node.value);
    renderNode(parent, child, depth + 1, childX, childWidth, subtreeDepth, path.concat(index));
    childX += childWidth;
  }
}

function renderFrames() {
  const frames = document.getElementById("frames");
  while (frames.firstChild) {
    frames.removeChild(frames.firstChild);
  }

  const focus = getNode(focusPath);
  const subtreeDepth = maxDepth(focus);
  renderNode(frames, focus, 0, SIDE_PADDING, INNER_WIDTH, subtreeDepth, focusPath.slice());
  updateHeader();
}

document.getElementById("reset-button").addEventListener("click", resetZoom);
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", renderFrames, { once: true });
} else {
  renderFrames();
}
